// NQxb_Artifact_Update_v1__Normalize_Request
// UPDATE-ONLY: Require artifact_id, reject if missing
// v2: Tags forwarding (T41 — Mutability Registry v2)

const raw = $json ?? {};

const body =
  raw.body && typeof raw.body === "object" && !Array.isArray(raw.body)
    ? raw.body
    : null;

const req = body ?? raw;

const asObj = (v) =>
  v && typeof v === "object" && !Array.isArray(v) ? v : {};

const artifact_id = req.artifact_id ?? null;
const artifact_type = (req.artifact_type ?? "").trim();

// UPDATE_ONLY: artifact_id is REQUIRED
if (!artifact_id || artifact_id.trim() === '') {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "UPDATE_ONLY",
          message: "artifact.update is update-only. Use artifact.create for new artifacts.",
          details: {
            hint: "artifact_id field is required for UPDATE operations."
          },
        },
      },
    },
  ];
}

// Tags canonicalization (Mutability Registry v2 — spine-level, type-agnostic)
const rawTags = req.tags ?? null;
let tags = null;
if (rawTags && typeof rawTags === 'object' && !Array.isArray(rawTags)) {
  const addArr = Array.isArray(rawTags.add) ? rawTags.add : [];
  const removeArr = Array.isArray(rawTags.remove) ? rawTags.remove : [];
  // Filter to strings only, deduplicate
  const addSet = [...new Set(addArr.filter(t => typeof t === 'string' && t.trim().length > 0).map(t => t.trim()))];
  const removeSet = [...new Set(removeArr.filter(t => typeof t === 'string' && t.trim().length > 0).map(t => t.trim()))];
  if (addSet.length > 0 || removeSet.length > 0) {
    tags = { add: addSet, remove: removeSet };
  }
}

const canonical = {
  gw_action: req.gw_action ?? "artifact.update",
  gw_workspace_id: req.gw_workspace_id ?? null,
  artifact_type: artifact_type,
  artifact_id: artifact_id.trim(),

  // Extension fields (only operational_state and state_reason allowed for project)
  extension: asObj(req.extension),

  // Tags (spine-level, type-agnostic per Mutability Registry v2)
  tags: tags,

  // deleted_at (BLOCKED - UNDECIDED per Mutability Registry v1)
  deleted_at: req.deleted_at ?? null,
};

canonical._gw_debug = {
  received_shape: body ? "body" : "flat",
  operation: "UPDATE",
  has_tags: tags !== null,
  has_extension: Object.keys(canonical.extension).length > 0,
};

return [{ json: canonical }];

// NQxb_Artifact_Update_v1__Validate_Request
// UPDATE-only validation (strict, predictable, preserves payload)
// v3.0: Extension optional when tags present (T41)

const req = $json ?? {};
const errors = [];

function isNonEmptyString(v) {
  return typeof v === "string" && v.trim().length > 0;
}

function asObj(v) {
  return v && typeof v === "object" && !Array.isArray(v) ? v : {};
}

// Required: gw_workspace_id
if (!isNonEmptyString(req.gw_workspace_id)) {
  errors.push({ field: "gw_workspace_id", reason: "required", expected: "uuid string" });
}

// Required: artifact_type
if (!isNonEmptyString(req.artifact_type)) {
  errors.push({ field: "artifact_type", reason: "required", expected: "non-empty string" });
}

// Required: artifact_id
if (!isNonEmptyString(req.artifact_id)) {
  errors.push({ field: "artifact_id", reason: "required", expected: "uuid string" });
}

// Extension validation: optional when tags present, but if present must be object
const hasExtension = req.extension && typeof req.extension === "object" && !Array.isArray(req.extension);
const hasTags = req.tags !== null && req.tags !== undefined;

if (req.extension !== undefined && req.extension !== null && !hasExtension) {
  // Extension was provided but is not a valid object
  errors.push({ field: "extension", reason: "invalid_type", expected: "object (if provided)" });
}

if (!hasExtension && !hasTags) {
  errors.push({ field: "extension_or_tags", reason: "required", expected: "at least one of: extension object, tags object" });
}

const ext = hasExtension ? asObj(req.extension) : {};

if (errors.length > 0) {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "VALIDATION_ERROR",
          message: "Validation failed for artifact.update (UPDATE)",
          details: {
            validation_errors: errors,
            operation: "UPDATE",
            artifact_type: req.artifact_type ?? null,
            artifact_id: req.artifact_id ?? null,
          },
        },
        gw_action: req.gw_action ?? "artifact.update",
        gw_workspace_id: req.gw_workspace_id ?? null,
        artifact_type: req.artifact_type ?? null,
        artifact_id: req.artifact_id ?? null,
        _gw_debug: req._gw_debug ?? undefined,
      },
    },
  ];
}

// Pass-through with normalized values
return [
  {
    json: {
      ...req,
      ok: true,
      _gw_route: "ok",
      gw_action: req.gw_action ?? "artifact.update",
      extension: ext,
      tags: req.tags ?? null,
      deleted_at: req.deleted_at ?? null,
      _gw_debug: {
        ...(req._gw_debug ?? {}),
        operation: "UPDATE",
        received_shape: (req._gw_debug && req._gw_debug.received_shape) ? req._gw_debug.received_shape : "flat",
      },
    },
  },
];

// Type Registry Guard
// Check artifact type against qxb_artifact_type_registry
// Error code: ARTIFACT_TYPE_NOT_ALLOWED
// Fail-closed: no row or disabled = reject

// Get original request from the Guard_Error_ShortCircuit node (ok path)
const originalRequest = $node['NQxb_Artifact_Update_v1__Guard_Error_ShortCircuit'].json;

// Get registry lookup result (may be empty if no row found)
const registryRow = $json;

const artifact_type = originalRequest.artifact_type;

// FAIL-CLOSED: No row found = type not registered
if (!registryRow || !registryRow.artifact_type) {
  return [{
    json: {
      ok: false,
      _gw_route: 'error',
      gw_action: originalRequest.gw_action ?? 'artifact.update',
      gw_workspace_id: originalRequest.gw_workspace_id ?? null,
      artifact_type: artifact_type,
      artifact_id: originalRequest.artifact_id ?? null,
      error: {
        code: 'ARTIFACT_TYPE_NOT_ALLOWED',
        message: `Artifact type '${artifact_type}' is not allowed`,
        details: {
          artifact_type: artifact_type,
          reason: 'not_registered',
          hint: 'Type must be registered in qxb_artifact_type_registry'
        }
      },
      timestamp: new Date().toISOString()
    }
  }];
}

// Type found but disabled
if (registryRow.enabled === false) {
  return [{
    json: {
      ok: false,
      _gw_route: 'error',
      gw_action: originalRequest.gw_action ?? 'artifact.update',
      gw_workspace_id: originalRequest.gw_workspace_id ?? null,
      artifact_type: artifact_type,
      artifact_id: originalRequest.artifact_id ?? null,
      error: {
        code: 'ARTIFACT_TYPE_NOT_ALLOWED',
        message: `Artifact type '${artifact_type}' is not allowed`,
        details: {
          artifact_type: artifact_type,
          reason: 'disabled',
          registry_enabled: false,
          hint: 'Type is registered but currently disabled'
        }
      },
      timestamp: new Date().toISOString()
    }
  }];
}

// Type is registered and enabled - pass through original request
return [{ json: originalRequest }];

// NQxb_Artifact_Update_v1__Check_Mutability_Rules
// Enforce Mutability Registry v2 rules
// v2: Tags-only bypass (T41) — spine-level tags are type-agnostic
//
// Order of checks:
// 1. Existence check (NOT_FOUND)
// 2. Tags-only bypass (all types) — NEW in v2
// 3. Immutability check (snapshot, restart)
// 4. Journal block (UNDECIDED_BLOCKED)
// 5. deleted_at block (UNDECIDED_BLOCKED)
// 6. Project extension field validation
// 7. Success path

const existing = $json;
const normalizeNode = $node['NQxb_Artifact_Update_v1__Normalize_Request'].json;

// 1. Check if artifact was found
if (!existing || !existing.artifact_id) {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "NOT_FOUND",
          message: "Artifact not found for UPDATE operation",
          details: {
            artifact_id: normalizeNode.artifact_id,
            workspace_id: normalizeNode.gw_workspace_id,
            operation: "UPDATE",
          },
        },
      },
    },
  ];
}

const artifact_type = existing.artifact_type?.trim();

// 2. Tags-only bypass (Mutability Registry v2)
// Tags are spine-level organizational metadata — type-agnostic.
// If ONLY tags are requested (no extension fields), bypass all type-specific blocks.
const normalizedTags = normalizeNode.tags ?? null;
const extensionKeys = Object.keys(normalizeNode.extension || {});
const isTagsOnly = normalizedTags !== null && extensionKeys.length === 0;

if (isTagsOnly) {
  return [
    {
      json: {
        ok: true,
        _gw_route: "ok",
        _update_mode: "tags_only",
        gw_action: normalizeNode.gw_action ?? "artifact.update",
        gw_workspace_id: normalizeNode.gw_workspace_id ?? null,
        artifact_id: existing.artifact_id,
        workspace_id: existing.workspace_id,
        artifact_type: artifact_type,
        _normalized_request: normalizeNode,
        _existing_artifact: existing,
        _gw_debug: {
          ...(normalizeNode._gw_debug ?? {}),
          mutability: "tags_only_bypass",
          operation: "UPDATE",
        },
      },
    },
  ];
}

// 3. RULE: snapshot and restart are fully immutable (Mutability Registry v1)
if (artifact_type === "snapshot" || artifact_type === "restart") {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "IMMUTABILITY_ERROR",
          message: `Artifact type '${artifact_type}' is immutable and cannot be updated. Only INSERT operations are allowed.`,
          details: {
            artifact_type: artifact_type,
            artifact_id: existing.artifact_id,
            operation_attempted: "UPDATE",
            registry_rule: "CREATE_ONLY",
            source: "Mutability Registry v2",
            hint: "Extension fields on immutable types cannot be updated. Tags-only updates are allowed via tags.add/tags.remove.",
          },
        },
      },
    },
  ];
}

// 4. RULE: journal mutability is UNDECIDED_BLOCKED (Mutability Registry v2)
// DOCTRINE: Journal INSERT-ONLY (Temporary)
if (artifact_type === "journal") {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "JOURNAL_MUTABILITY_UNDECIDED",
          message:
            "Journal update policy is not locked. Use artifact.create to append new entries.",
          details: {
            artifact_type: "journal",
            artifact_id: existing.artifact_id,
            operation_attempted: "UPDATE",
            registry_rule: "UNDECIDED_BLOCKED",
            source: "Mutability Registry v2",
            doctrine: "Journal INSERT-ONLY (Temporary)",
            hint: "Journal extension fields are blocked until mutability policy is locked. Tags-only updates are allowed via tags.add/tags.remove.",
          },
        },
      },
    },
  ];
}

// 5. RULE: deleted_at is UNDECIDED_BLOCKED (Mutability Registry v1)
if (normalizeNode.deleted_at !== null && normalizeNode.deleted_at !== undefined) {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "MUTABILITY_ERROR",
          message: "Field 'deleted_at' is UNDECIDED_BLOCKED and cannot be updated.",
          details: {
            field: "deleted_at",
            artifact_type: artifact_type,
            artifact_id: existing.artifact_id,
            registry_rule: "UNDECIDED_BLOCKED",
            source: "Mutability Registry v1",
            hint: "Soft delete semantics not yet locked. Use dedicated artifact.delete action when implemented.",
          },
        },
      },
    },
  ];
}

// 6. RULE: For project artifacts, only operational_state and state_reason allowed
if (artifact_type === "project") {
  const extension = normalizeNode.extension || {};
  const allowedFields = ["operational_state", "state_reason"];
  const providedFields = Object.keys(extension);

  const disallowedFields = providedFields.filter((f) => !allowedFields.includes(f));

  if (disallowedFields.length > 0) {
    if (disallowedFields.includes("lifecycle_stage")) {
      return [
        {
          json: {
            ok: false,
            _gw_route: "error",
            error: {
              code: "MUTABILITY_ERROR",
              message:
                "Field 'lifecycle_stage' is PROMOTE_ONLY and cannot be updated via artifact.update.",
              details: {
                field: "extension.lifecycle_stage",
                artifact_type: "project",
                artifact_id: existing.artifact_id,
                registry_rule: "PROMOTE_ONLY",
                source: "Mutability Registry v1",
                hint: "Use artifact.promote operation to change lifecycle_stage.",
              },
            },
          },
        },
      ];
    }

    return [
      {
        json: {
          ok: false,
          _gw_route: "error",
          error: {
            code: "MUTABILITY_ERROR",
            message: `Disallowed fields in extension for project UPDATE: ${disallowedFields.join(
              ", "
            )}`,
            details: {
              disallowed_fields: disallowedFields,
              allowed_fields: allowedFields,
              artifact_type: "project",
              artifact_id: existing.artifact_id,
              source: "Mutability Registry v1",
              hint: "Only operational_state and state_reason are UPDATE_ALLOWED for project artifacts.",
            },
          },
        },
      },
    ];
  }

  if (providedFields.length === 0) {
    return [
      {
        json: {
          ok: false,
          _gw_route: "error",
          error: {
            code: "VALIDATION_ERROR",
            message: "No updateable fields provided in extension for project UPDATE.",
            details: {
              artifact_type: "project",
              artifact_id: existing.artifact_id,
              allowed_fields: allowedFields,
              hint: "Provide at least one of: operational_state, state_reason",
            },
          },
        },
      },
    ];
  }
}

// 7. Mutability checks passed — extension update path
return [
  {
    json: {
      ok: true,
      _gw_route: "ok",
      _update_mode: "extension",
      gw_action: normalizeNode.gw_action ?? "artifact.update",
      gw_workspace_id: normalizeNode.gw_workspace_id ?? null,
      artifact_id: existing.artifact_id,
      workspace_id: existing.workspace_id,
      artifact_type: existing.artifact_type,
      _normalized_request: normalizeNode,
      _existing_artifact: existing,
      _gw_debug: {
        ...(normalizeNode._gw_debug ?? {}),
        mutability: "passed",
        operation: "UPDATE",
      },
    },
  },
];

// NQxb_Artifact_Update_v1__Compute_Tag_Merge
// Merges existing spine tags with add/remove operations.
// Rules:
// - Deduplicate
// - Remove explicitly removed tags (remove wins over add)
// - Deterministic ordering (alphabetical sort)
// - Never return null (empty array allowed)
// - Computes next_version for spine update

const normalizeNode = $node['NQxb_Artifact_Update_v1__Normalize_Request'].json;
const existing = $json._existing_artifact;

const existingTags = Array.isArray(existing.tags) ? existing.tags : [];
const tagsToAdd = Array.isArray(normalizeNode.tags?.add) ? normalizeNode.tags.add : [];
const tagsToRemove = new Set(
  Array.isArray(normalizeNode.tags?.remove) ? normalizeNode.tags.remove : []
);

// Build merged set: existing + add, then subtract remove
const merged = new Set(existingTags);
for (const tag of tagsToAdd) {
  merged.add(tag);
}
for (const tag of tagsToRemove) {
  merged.delete(tag);
}

// Deterministic ordering (alphabetical)
const finalTags = [...merged].sort();

// Version increment
const currentVersion = typeof existing.version === 'number' ? existing.version : 1;
const nextVersion = currentVersion + 1;

return [{
  json: {
    artifact_id: existing.artifact_id,
    workspace_id: existing.workspace_id,
    artifact_type: existing.artifact_type,
    final_tags: finalTags,
    next_version: nextVersion,
    _tag_debug: {
      existing: existingTags,
      added: tagsToAdd,
      removed: [...tagsToRemove],
      result: finalTags,
      version_before: currentVersion,
      version_after: nextVersion,
    },
  },
}];

// NQxb_Artifact_Update_v1__Return_Tags_Ack
// Terminal node for tags-only update path.
// Uses $node[] references (HTTP Request output may be empty with return=minimal).

const normalizeNode = $node['NQxb_Artifact_Update_v1__Normalize_Request'].json;
const tagMergeNode = $node['NQxb_Artifact_Update_v1__Compute_Tag_Merge'].json;

return [{
  json: {
    ok: true,
    gw_action: "artifact.update",
    operation: "TAG_UPDATE",
    artifact_id: normalizeNode.artifact_id,
    artifact_type: normalizeNode.artifact_type,
    gw_workspace_id: normalizeNode.gw_workspace_id,
    tags: tagMergeNode.final_tags,
    version: tagMergeNode.next_version,
    _tag_changes: {
      added: normalizeNode.tags?.add ?? [],
      removed: normalizeNode.tags?.remove ?? [],
    },
    _kgb: {
      status: "TAG_UPDATE_CONFIRMED",
      note: "Spine-level tag update completed. Version incremented. updated_at set by trigger.",
    },
  },
}];

// NQxb_Artifact_Update_v1__Prepare_Project_Extension_Update
// Extract allowed fields (operational_state, state_reason) for project UPDATE

const normalizeNode = $json._normalized_request;
const extension = normalizeNode.extension || {};

// Only update fields that are explicitly provided
const hasOperationalState = 'operational_state' in extension;
const hasStateReason = 'state_reason' in extension;

const updateFields = {
  artifact_id: $json.artifact_id,
};

if (hasOperationalState) {
  updateFields.operational_state = extension.operational_state;
}

if (hasStateReason) {
  updateFields.state_reason = extension.state_reason;
}

updateFields._has_operational_state = hasOperationalState;
updateFields._has_state_reason = hasStateReason;

return [{ json: updateFields }];

// NQxb_Artifact_Update_v1__Prepare_Query_Call
// Get artifact_id from the flow for final query

const normalizeNode = $node['NQxb_Artifact_Update_v1__Normalize_Request'].json;
const mutabilityNode = $node['NQxb_Artifact_Update_v1__Check_Mutability_Rules'].json;

const artifact_id = mutabilityNode.artifact_id || normalizeNode.artifact_id;

return [
  {
    json: {
      saved_artifact_id: artifact_id,
      saved_workspace_id: normalizeNode.gw_workspace_id,
      saved_artifact_type: mutabilityNode.artifact_type || normalizeNode.artifact_type,
    },
  },
];

// NQxb_Artifact_Update_v1__Build_Query_Request
// Build a *correct* artifact.query request after UPDATE, even if the DB Update node outputs {}.
//
// Key idea: NEVER trust $json here because Supabase Update often returns an empty item.
// Instead, pull canonical IDs from the Normalize node (or other stable upstream nodes).

const normalize = $node["NQxb_Artifact_Update_v1__Normalize_Request"]?.json ?? {};
const validate   = $node["NQxb_Artifact_Update_v1__Validate_Request"]?.json ?? {};

const gw_workspace_id = normalize.gw_workspace_id ?? validate.gw_workspace_id ?? null;
const artifact_type   = normalize.artifact_type   ?? validate.artifact_type   ?? null;
const artifact_id     = normalize.artifact_id     ?? validate.artifact_id     ?? null;

return [
  {
    json: {
      gw_action: "artifact.query",
      gw_workspace_id,
      artifact_type,
      artifact_id,
      selector: {
        hydrate: true,
      },
      _gw_debug: {
        routed_from: "NQxb_Artifact_Update_v1",
        next: "artifact.query (hydrate)",
        source_ids: {
          gw_workspace_id,
          artifact_type,
          artifact_id,
        },
      },
    },
  },
];

// KGB TERMINAL — UPDATE ONLY
// Never trust Supabase UPDATE output.
// Always return a stable acknowledgement.

const normalize = $node["NQxb_Artifact_Update_v1__Normalize_Request"].json;

return [
  {
    json: {
      ok: true,
      gw_action: "artifact.update",
      operation: "UPDATE",
      artifact_id: normalize.artifact_id,
      artifact_type: normalize.artifact_type,
      gw_workspace_id: normalize.gw_workspace_id,
      updated_fields: Object.keys(normalize.extension || {}),
      _kgb: {
        status: "UPDATE_CONFIRMED",
        note: "Update completed. Query intentionally not invoked.",
      },
    },
  },
];

// NQxb_Artifact_Update_v1__Return_Error_Passthrough
// Terminal node: pass-through the incoming payload unchanged.
// Use for any error path to guarantee the workflow returns a real JSON envelope
// instead of dead-ending into "".

return $input.all();
